const redditPosts = $node["Get Reddit Data"].json.data.children || [];
const history = $node["Get History"].json || [];
const historyArray = Array.isArray(history) ? history : [history];
const historyIds = new Set(historyArray.map(row => row.reddit_id).filter(id => !!id));

const filtered = redditPosts.filter(post => !historyIds.has(post.data.id));
return { posts: filtered.map(p => ({ id: p.data.id, title: p.data.title, text: p.data.selftext })) };
